import "./App.css";
import Slider from "./Slider";
import Nav from "./nav";
import Tooler from "./tooler";
import MyProjects from "./myProjects";
import Footer from "./Footer";

function App() {
  return (
    <div className="App">
      <div className="header">
        <h3 className="tomasRadic">RADICC</h3>
        <Nav />
      </div>
      <div className="body">
        <h1 className="tomRadText">A fronEnd developer.</h1>
        <Slider />
      </div>
      <Tooler />
      <MyProjects />
      <Footer />
    </div>
  );
}
export default App;
